css:
.loader {color: var(--loader-color, #b45309);
  --loader-secondary-color: #fcd34d;
  --loader-bg: #ffffff;
   width: 68px;
   aspect-ratio: 1;
   border: 8px solid currentColor;
   box-sizing: border-box;
   background: linear-gradient(currentColor 0 0) 2px 50% /10px 20px, linear-gradient(currentColor 0 0) 48px 50%/10px 20px, linear-gradient(currentColor 0 0) center/100% 20px, radial-gradient(farthest-side,#0000 calc(98% - 10px),currentColor calc(100% - 10px) 98%,#0000), currentColor;
   background-repeat: no-repeat;
   filter: blur(4px) contrast(10);
   animation: l15 0.6s infinite alternate;
}
@keyframes l15  {
  0%,30% {background-position:2px 50%,48px 50%,center,0 0}
100% {background-position:10px 50%,40px 50%,center,0 0}
}
